_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 aspect_ts = vec2(1, uTexSize.y/uTexSize.x); //Self-made uTexSize uAspect-correcting
    vUv = vUv*2 - 1;
    vUv *= aspect_ts;
    vUv.y = -vUv.y; //Y flip for equivalency of ShaderToy

    vec3 p, c = 0;
    float z = 0.0;
    float d, l;

    for (float i = 1; i <= 60; i++)
    {
        // Ray setup
        vec3 ray_dir = normalize(vec3(vUv*2, -1));
        p = z * ray_dir + sin(0.5 * uTime);

        // Camera position
        p.z += 5;

        // Rotation matrix with uTime and y-dependent phase
        float angle = uTime + p.y * .4;
        mat2 rot_mat = transpose(mat2(cos(angle), -sin(angle), sin(angle), cos(angle)));
        // In GLSL is column-major order and in HLSL, row-major order,
        // So we transpose the matrix with transpose() to be the same as GLSL.
        p.xz = multiply(rot_mat, p.xz);

        // Distance to base sphere
        d = length(p);

        // Light distance calculation
        l = length(cos(p / (d * .1)) + p.y + d);

        // UFO shape distance field
        vec3 exp_calc = exp(-p*p / .1);
        float ufo_shape = d - 0.8 - exp_calc.y;

        // Step distance(minimum of light distance and UFO shape)
        d = min(l, ufo_shape) / 9;

        // March forward
        z += d;

        // Color accumulation
        c += vec3(5, 9, 2 + d * 50) / (l * z);
    }

    // Tonemapping
    //XorDev - told me to replace tanh(x) with 1-exp(-x), which it works.
    vec3 result = c * c / 7e3; //Make this as a separate result.
    ret = 1-exp(-result); //Then output tonemapping without thresholding.

  fragColor = ret;
}

